_E2B = {v: k for k, v in enumerate(_PAL)}

def _eb(txt):
    r=[]; b=""
    for c in txt:
        b+=c
        if b in _E2B: r.append(_E2B[b]); b=""
    return bytes(r)

def _xc(d,k):
    kl=len(k); return bytes(d[i]^k[i%kl] for i in range(len(d)))

def _rk(s):
    rs=base64.b64decode('EzfA3vrOsAsRIjNEVWZ3iA==')
    return hashlib.sha256(struct.pack(">Q",s)+rs).digest()

def _decode_blob(seed,blob):
    return zlib.decompress(_xc(base64.b85decode(_eb(blob)),_rk(seed)))

# ── password gate (decode path only) ─────────────────────────────
_DSB='3q2+78r+ur4BI0VniavN7w=='
_PH='7928d0bdcfa7c4ed9e71fea4b63b9268f9499357094e01efd63a02566e2f4589'

def _vp(pw):
    ds=base64.b64decode(_DSB)
    k=hashlib.pbkdf2_hmac("sha256",pw.encode(),ds,200000,dklen=32)
    return hmac.compare_digest(hashlib.sha256(k).hexdigest(),_PH)

# ── dispatch ──────────────────────────────────────────────────
def _run():
    raw=_decode_blob(_SEED,_BLOB)
    if hashlib.sha256(raw).hexdigest()!=_CSUM: sys.exit("❌ Integrity check failed.")
    g=dict(__name__="__main__",__file__=__file__,__spec__=None,__loader__=None,__builtins__=__builtins__)
    exec(compile(raw.decode("utf-8"),__file__,"exec"),g)

def _extract():
    pw=input("🔐 Enter decode password: ")
    if not _vp(pw): print("❌ Wrong password. Access denied."); sys.exit(1)
    raw=_decode_blob(_SEED,_BLOB)
    if hashlib.sha256(raw).hexdigest()!=_CSUM: sys.exit("❌ Integrity check failed.")
    print("\n"+"-"*60)
    print(raw.decode("utf-8"))
    print("-"*60)

if __name__=="__main__":
    if "--decode" in sys.argv or "--extract" in sys.argv: _extract()
    else: _run()
